-/// Get ANSI color code for severity level.
-fn severity_color_code(severity: Severity) -> u8 {
-    match severity {
-        Severity::Critical => 31, // Red
-        Severity::High => 91,     // Bright red
-        Severity::Medium => 33,   // Yellow
-        Severity::Low => 34,      // Blue
-    }
-}
